// Extraer el JSON del output del agente
const raw = $input.first().json.output;

let summary;
try {
  // Buscar el JSON aunque venga con texto alrededor
  const match = raw.match(/\{[\s\S]*\}/);
  summary = JSON.parse(match[0]);
} catch (e) {
  return [{ json: { text: "⚠️ Error al parsear el resumen del agente." } }];
}

const urgencyEmoji = {
  "Alta": "🔴",
  "Media": "🟡",
  "Baja": "🟢"
};

const statusEmoji = {
  "Resuelto": "✅",
  "Pendiente": "⏳",
  "Escalado": "📌",
  "Sospechoso": "⚠️"
};

const msg = `
🤖 *Resumen de Conversación*
━━━━━━━━━━━━━━━━━━━━
📅 *Fecha:* ${summary.fecha}
👤 *Usuario:* ${summary.usuario_identificado}
💬 *Turnos:* ${summary.duracion_turnos}
📋 *Tema:* ${summary.tema_principal}

📝 *Resumen:*
${summary.resumen_ejecutivo}

🔑 *Puntos Clave:*
${summary.puntos_clave.map(p => `• ${p}`).join('\n')}

▶️ *Acción Requerida:* ${summary.accion_requerida}

${urgencyEmoji[summary.nivel_urgencia] || '⚪'} *Urgencia:* ${summary.nivel_urgencia}
${statusEmoji[summary.estado] || '❓'} *Estado:* ${summary.estado}

${summary.alertas_seguridad !== 'Ninguna' ? `⚠️ *ALERTA DE SEGURIDAD:* ${summary.alertas_seguridad}` : '🔒 Sin alertas de seguridad'}
━━━━━━━━━━━━━━━━━━━━
`;

return [{ json: { text: msg } }];

